SELECT id, room_id, sender_user_id, kind, content, created_at
FROM room_chat_message
WHERE id = #{id}

SELECT id, room_id, sender_user_id, kind, content, created_at
FROM (
         SELECT id, room_id, sender_user_id, kind, content, created_at
         FROM room_chat_message
         WHERE room_id = #{roomId}
         ORDER BY id DESC
         LIMIT #{limit}
     ) t
ORDER BY id ASC
